const items = $input.all();

items.forEach(item => {
  if (item.json && item.json['ID Laporan']) {
    // Tambahkan kolom "Sumber" berdasarkan ID awal
    if (item.json['ID Laporan'].startsWith('REP')) {
      item.json.Sumber = 'Sheet1';
    } else if (item.json['ID Laporan'].startsWith('LAP')) {
      item.json.Sumber = 'Sheet2';
    } else {
      item.json.Sumber = 'Unknown';
    }
  }
});

return items;

// Ambil semua item dari input (aman untuk semua mode)
const inputData = $input.all();

// Ekstrak semua baris dari semua item
const allRows = inputData.flatMap(item =>
  Array.isArray(item.json) ? item.json : [item.json]
);

// Proses tiap baris
allRows.forEach(row => {
  if (typeof row === 'object' && row !== null) {
    if (row['ID Laporan']) row['ID Laporan'] = String(row['ID Laporan']).trim();
    if (row.Bulan) row.Bulan = String(row.Bulan).trim();
    if (row['Kategori Produk']) row['Kategori Produk'] = String(row['Kategori Produk']).trim();
    if (row['Nama Produk']) row['Nama Produk'] = String(row['Nama Produk']).trim();

    row['Jumlah Stok'] = parseFloat(row['Jumlah Stok']) || 0;
    row['Penjualan Harian'] = parseFloat(row['Penjualan Harian']) || 0;
    row['Harga Satuan (IDR)'] = parseFloat(row['Harga Satuan (IDR)']) || 0;
    row['Total Penjualan (IDR)'] = parseFloat(row['Total Penjualan (IDR)']) || 0;
  }
});

// Kembalikan sebagai daftar item terpisah
return allRows.map(row => ({ json: row }));

// Ambil semua input (untuk aman di semua mode)
const inputData = $input.all();

// Ekstrak semua baris
const allRows = inputData.flatMap(item =>
  Array.isArray(item.json) ? item.json : [item.json]
);

// Transformasi setiap baris
const transformedRows = allRows.map(row => {
  // Gabung Kategori + Nama Produk untuk kolom "Produk"
  const produk = `${row['Kategori Produk'] || ''} ${row['Nama Produk'] || ''}`.trim();

  // Buat objek baru dengan format Sheet 1 & 2
  return {
    'ID Laporan': row['ID Laporan'] ? String(row['ID Laporan']).trim() : '',
    'Bulan': row.Bulan ? String(row.Bulan).trim() : '',
    'Produk': produk,
    'Wilayah': '-', // default, bisa diisi jika ada info wilayah
    'Penjualan (Unit)': parseFloat(row['Penjualan Harian']) || 0,
    'Target (Unit)': 0, // default, bisa diisi jika ada target
    'Pendapatan (IDR)': parseFloat(row['Total Penjualan (IDR)']) || 0,
    'Status': row['Karyawan Penanggung Jawab'] ? String(row['Karyawan Penanggung Jawab']).trim() : 'Tidak Diketahui',
    'Keterangan': row['Catatan Status'] ? String(row['Catatan Status']).trim() : '',
    'Tanggal Laporan': row.Bulan ? `${row.Bulan} 01, ${new Date().getFullYear()}` : ''
  };
});

// Kembalikan sebagai array item terpisah
return transformedRows.map(row => ({ json: row }));

// Ambil semua input (untuk aman di semua mode)
const inputData = $input.all();

// Ekstrak semua baris
const allRows = inputData.flatMap(item =>
  Array.isArray(item.json) ? item.json : [item.json]
);

// Transformasi setiap baris
const transformedRows = allRows.map(row => {
  // Gabung Kategori + Nama Produk untuk kolom "Produk"
  const produk = `${row['Kategori Produk'] || ''} ${row['Nama Produk'] || ''}`.trim();

  // Buat objek baru dengan format Sheet 1 & 2
  return {
    'ID Laporan': row['ID Laporan'] ? String(row['ID Laporan']).trim() : '',
    'Bulan': row.Bulan ? String(row.Bulan).trim() : '',
    'Produk': produk,
    'Wilayah': '-', // default, bisa diisi jika ada info wilayah
    'Penjualan (Unit)': parseFloat(row['Penjualan Harian']) || 0,
    'Target (Unit)': 0, // default, bisa diisi jika ada target
    'Pendapatan (IDR)': parseFloat(row['Total Penjualan (IDR)']) || 0,
    'Status': row['Karyawan Penanggung Jawab'] ? String(row['Karyawan Penanggung Jawab']).trim() : 'Tidak Diketahui',
    'Keterangan': row['Catatan Status'] ? String(row['Catatan Status']).trim() : '',
    'Tanggal Laporan': row.Bulan ? `${row.Bulan} 01, ${new Date().getFullYear()}` : ''
  };
});

// Kembalikan sebagai array item terpisah
return transformedRows.map(row => ({ json: row }));

// Ambil SEMUA input dari semua jalur
const allInputs = $input.all();

// Gabungkan semua baris dari semua input
const allRows = allInputs.flatMap(item =>
  Array.isArray(item.json) ? item.json : [item.json]
);

// Filter hanya bulan ini
const now = new Date();
const currentMonthName = now.toLocaleString('id-ID', { month: 'long' });
const currentYear = now.getFullYear();

const monthlyData = allRows.filter(row => 
  String(row.Bulan || '').toLowerCase() === currentMonthName.toLowerCase()
);

// Hitung metrik
const totalPenjualanUnit = monthlyData.reduce((sum, r) => sum + (r['Penjualan (Unit)'] || 0), 0);
const totalPendapatan = monthlyData.reduce((sum, r) => sum + (r['Pendapatan (IDR)'] || 0), 0);
const totalLaporan = monthlyData.length;

// Buat ringkasan
const laporan = {
  'Bulan': currentMonthName,
  'Tahun': currentYear,
  'Jumlah_Laporan': totalLaporan,
  'Total_Penjualan_Unit': totalPenjualanUnit,
  'Total_Pendapatan_IDR': totalPendapatan,
  'Rata_Rata_Penjualan_Per_Laporan': totalLaporan ? (totalPenjualanUnit / totalLaporan).toFixed(2) : 0,
  'Rata_Rata_Pendapatan_Per_Laporan': totalLaporan ? (totalPendapatan / totalLaporan).toFixed(2) : 0,
  'Sumber_Data': 'Sheet 1, Sheet 2, Sheet 3',
  'Terakhir_Diperbarui': new Date().toISOString()
};

// Kembalikan HANYA 1 item
return [{ json: laporan }];

